"use client";

import { useState } from "react";
import styles from "@/app/page.module.css";

interface Category {
  name: string;
  slug: string;
}

interface Video {
  id: number;
  title: string;
  description: string | null;
  type: string;
  url: string;
  thumbnail: string | null;
  views: number;
  likes: number;
  isFeatured: boolean;
  createdAt: Date | string;
  category?: Category | null;
}

interface YouTubeGridProps {
  initialVideos: Video[];
}

export default function YouTubeGrid({ initialVideos }: YouTubeGridProps) {
  const [activeVideo, setActiveVideo] = useState<Video | null>(null);
  const [modalTab, setModalTab] = useState<"description" | "contact">("description");

  // Reset tab selection when video changes
  const handleSelectVideo = (video: Video) => {
    setModalTab("description");
    setActiveVideo(video);
  };

  // Parse standard YouTube URL to get the secure embed URL
  const getEmbedUrl = (url: string) => {
    if (url.includes("embed/")) {
      return `${url}?autoplay=1&rel=0`;
    }
    
    let videoId = "";
    if (url.includes("youtube.com/watch")) {
      const parts = url.split("v=");
      if (parts[1]) {
        videoId = parts[1].split("&")[0];
      }
    } else if (url.includes("youtu.be/")) {
      const parts = url.split("youtu.be/");
      if (parts[1]) {
        videoId = parts[1].split("?")[0];
      }
    }

    if (videoId) {
      return `https://www.youtube.com/embed/${videoId}?autoplay=1&rel=0`;
    }
    return url;
  };

  // Helper to extract YouTube video ID for clean default thumbnail fallback
  const getFallbackThumbnail = (url: string) => {
    let videoId = "default";
    if (url.includes("embed/")) {
      const parts = url.split("embed/");
      if (parts[1]) videoId = parts[1].split("?")[0];
    } else if (url.includes("v=")) {
      const parts = url.split("v=");
      if (parts[1]) videoId = parts[1].split("&")[0];
    } else if (url.includes("youtu.be/")) {
      const parts = url.split("youtu.be/");
      if (parts[1]) videoId = parts[1].split("?")[0];
    }
    return `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`;
  };

  if (initialVideos.length === 0) {
    return (
      <div className={styles.emptyState}>
        <h3>لا توجد فيديوهات في هذا القسم حالياً</h3>
        <p style={{ marginTop: "8px" }}>تفضل بزيارة الأقسام الأخرى أو تصفح البث المباشر والريلز!</p>
      </div>
    );
  }

  return (
    <>
      <div className={styles.postsGrid}>
        {initialVideos.map((video) => (
          <div
            key={video.id}
            className={`${styles.postCard} glass-card`}
            style={{ cursor: "pointer" }}
            onClick={() => handleSelectVideo(video)}
          >
            <div className={styles.thumbnailWrapper}>
              <img
                src={video.thumbnail || getFallbackThumbnail(video.url)}
                alt={video.title}
              />
              {video.category && <span className={styles.postTag}>{video.category.name}</span>}
              <div className={styles.playIconWrapper} style={{ opacity: 1, transform: "translate(-50%, -50%) scale(1)" }}>
                <span style={{ fontSize: "1.3rem", color: "#fff" }}>▶</span>
              </div>
            </div>
            
            <div className={styles.postDetails}>
              <h3 className={styles.postTitle}>{video.title}</h3>
              {video.description && <p className={styles.postDesc}>{video.description}</p>}
              <div className={styles.postMeta}>
                <span>📅 {new Date(video.createdAt).toLocaleDateString("ar-LY")}</span>
              </div>
              <button
                onClick={(e) => {
                  e.stopPropagation(); // Avoid double trigger
                  handleSelectVideo(video);
                }}
                className="btn btn-secondary"
                style={{ marginTop: "14px", width: "100%", fontSize: "0.85rem", gap: "6px" }}
              >
                📺 شاهد الآن واقرأ التفاصيل
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Cinematic Widescreen Lightbox Overlay Modal */}
      {activeVideo && (
        <div
          onClick={() => setActiveVideo(null)}
          style={{
            position: "fixed",
            inset: 0,
            backgroundColor: "rgba(3, 4, 7, 0.95)",
            backdropFilter: "blur(20px)",
            WebkitBackdropFilter: "blur(20px)",
            zIndex: 3000,
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            padding: "20px",
          }}
        >
          {/* Main Enclosure */}
          <div
            onClick={(e) => e.stopPropagation()} // Guard from closing overlay on inner clicks
            style={{
              width: "100%",
              maxWidth: "1150px",
              background: "rgba(11, 15, 26, 0.9)",
              border: "1px solid rgba(255, 255, 255, 0.08)",
              borderRadius: "24px",
              padding: "24px",
              boxShadow: "0 25px 70px rgba(0, 0, 0, 0.8)",
              display: "flex",
              flexDirection: "column",
              gap: "20px",
            }}
          >
            {/* Header */}
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
                <span className={styles.postTag} style={{ position: "static" }}>
                  {activeVideo.category ? activeVideo.category.name : "فيديو مميز"}
                </span>
                <h3 style={{ color: "#fff", fontSize: "1.2rem", fontWeight: "800", margin: 0 }}>
                  {activeVideo.title}
                </h3>
              </div>
              <button
                onClick={() => setActiveVideo(null)}
                style={{
                  background: "rgba(255, 255, 255, 0.05)",
                  border: "1px solid rgba(255, 255, 255, 0.08)",
                  width: "40px",
                  height: "40px",
                  borderRadius: "50%",
                  color: "#fff",
                  fontSize: "1.2rem",
                  cursor: "pointer",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  transition: "all 0.2s",
                }}
              >
                ✕
              </button>
            </div>

            {/* Split Screen Columns */}
            <div style={{ display: "flex", gap: "24px", flexDirection: "row", flexWrap: "wrap" }}>
              {/* Column 1: Cinematic Iframe Video Player */}
              <div
                style={{
                  flex: "1 1 62%",
                  minWidth: "320px",
                  aspectRatio: "16/9",
                  borderRadius: "20px",
                  overflow: "hidden",
                  border: "1px solid rgba(255, 255, 255, 0.1)",
                  background: "#000",
                  boxShadow: "0 10px 30px rgba(0, 0, 0, 0.6)",
                }}
              >
                <iframe
                  src={getEmbedUrl(activeVideo.url)}
                  title={activeVideo.title}
                  style={{ width: "100%", height: "100%", border: "none" }}
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                  allowFullScreen
                />
              </div>

              {/* Column 2: Gorgeous Scrolling Tabbed Sidebar */}
              <div
                style={{
                  flex: "1 1 32%",
                  minWidth: "280px",
                  display: "flex",
                  flexDirection: "column",
                  gap: "16px",
                  background: "rgba(255, 255, 255, 0.02)",
                  border: "1px solid rgba(255, 255, 255, 0.05)",
                  borderRadius: "20px",
                  padding: "20px",
                  maxHeight: "360px",
                  overflowY: "auto",
                }}
              >
                {/* Tab Controls */}
                <div style={{ display: "flex", borderBottom: "1px solid rgba(255, 255, 255, 0.08)", paddingBottom: "10px", gap: "10px" }}>
                  <button
                    onClick={() => setModalTab("description")}
                    style={{
                      flex: 1,
                      padding: "8px 12px",
                      background: modalTab === "description" ? "var(--primary)" : "transparent",
                      border: "none",
                      color: "#fff",
                      fontSize: "0.85rem",
                      fontWeight: "700",
                      borderRadius: "8px",
                      cursor: "pointer",
                      transition: "all 0.2s"
                    }}
                  >
                    📄 تفاصيل التقرير
                  </button>
                  <button
                    onClick={() => setModalTab("contact")}
                    style={{
                      flex: 1,
                      padding: "8px 12px",
                      background: modalTab === "contact" ? "var(--primary)" : "transparent",
                      border: "none",
                      color: "#fff",
                      fontSize: "0.85rem",
                      fontWeight: "750",
                      borderRadius: "8px",
                      cursor: "pointer",
                      transition: "all 0.2s"
                    }}
                  >
                    💬 تواصل معنا
                  </button>
                </div>

                {/* Tab 1: Video Description */}
                {modalTab === "description" && (
                  <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.8rem", color: "var(--text-secondary)", borderBottom: "1px solid rgba(255, 255, 255, 0.05)", paddingBottom: "10px" }}>
                      <span>📅 {new Date(activeVideo.createdAt).toLocaleDateString("ar-LY")}</span>
                    </div>
                    <p style={{ color: "#cbd5e1", fontSize: "0.88rem", lineHeight: "1.7", margin: 0 }}>
                      {activeVideo.description || "لا يوجد وصف متوفر لهذا الفيديو حالياً."}
                    </p>
                  </div>
                )}

                {/* Tab 2: Direct Contact Form/Channels */}
                {modalTab === "contact" && (
                  <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
                    <p style={{ fontSize: "0.82rem", color: "#94a3b8", lineHeight: "1.6", margin: 0 }}>
                      لديك استفسار أو ترغب في الإعلان في قنوات ليبيا بلس بخصوص هذا التقرير؟ تواصل فوراً مع فريق الإدارة عبر إحدى القنوات الآتية:
                    </p>
                    <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
                      <a
                        href={`https://wa.me/218910000000?text=${encodeURIComponent("السلام عليكم، أرغب في الاستفسار أو الإعلان بخصوص التقرير: " + activeVideo.title)}`}
                        target="_blank"
                        rel="noopener noreferrer"
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          gap: "8px",
                          padding: "10px",
                          background: "rgba(34, 197, 94, 0.1)",
                          border: "1px solid rgba(34, 197, 94, 0.2)",
                          borderRadius: "10px",
                          color: "#22c55e",
                          fontWeight: "750",
                          textDecoration: "none",
                          fontSize: "0.82rem",
                          transition: "all 0.2s"
                        }}
                      >
                        🟢 واتساب الإدارة المباشر
                      </a>

                      <a
                        href="https://t.me/libyaplus_ad"
                        target="_blank"
                        rel="noopener noreferrer"
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          gap: "8px",
                          padding: "10px",
                          background: "rgba(14, 165, 233, 0.1)",
                          border: "1px solid rgba(14, 165, 233, 0.2)",
                          borderRadius: "10px",
                          color: "#0ea5e9",
                          fontWeight: "750",
                          textDecoration: "none",
                          fontSize: "0.82rem",
                          transition: "all 0.2s"
                        }}
                      >
                        🔵 تيليجرام الإدارة المباشر
                      </a>

                      <a
                        href="tel:+218910000000"
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          gap: "8px",
                          padding: "10px",
                          background: "rgba(225, 29, 72, 0.1)",
                          border: "1px solid rgba(225, 29, 72, 0.2)",
                          borderRadius: "10px",
                          color: "var(--primary)",
                          fontWeight: "750",
                          textDecoration: "none",
                          fontSize: "0.82rem",
                          transition: "all 0.2s"
                        }}
                      >
                        📞 اتصل بنا هاتفياً
                      </a>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
